const Web3 = require('web3');
const { ethers } = require('ethers');

// Initialize Web3 with Infura or another provider
const web3Provider = new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID');
const web3 = new Web3(web3Provider);

// Wallet configuration with private key for signing transactions
const privateKey = 'YOUR_PRIVATE_KEY';
const wallet = new ethers.Wallet(privateKey, web3Provider);

async function sendETH(toAddress, amount) {
    try {
        const tx = await wallet.sendTransaction({
            to: toAddress,
            value: web3.utils.toWei(amount.toString(), 'ether')
        });
        return tx;
    } catch (error) {
        console.error('Error sending ETH:', error);
        throw error;
    }
}

async function interactWithSmartContract(contractAddress, contractABI, method, params) {
    try {
        const contract = new ethers.Contract(contractAddress, contractABI, wallet);
        const tx = await contract[method](...params);
        return tx;
    } catch (error) {
        console.error('Error interacting with smart contract:', error);
        throw error;
    }
}

// Example usage
